CREATE TABLE items(id INT, category VARCHAR, value INT);
INSERT INTO items VALUES (1, 'A', 10), (2, 'A', NULL), (3, 'B', 20), (4, 'B', 30);

-- Returns one non-NULL value for each category. The specific value is non-deterministic.
SELECT category, any_value(value) FROM items GROUP BY category;

CREATE TABLE test_scores (student_name VARCHAR, score INT);
INSERT INTO test_scores VALUES ('Alice', 95), ('Bob', 85), ('Charlie', 95), (NULL, 100), ('David', NULL);
SELECT arg_max_null(student_name, score) FROM test_scores;

CREATE TABLE sales (product VARCHAR, sale_date DATE);
INSERT INTO sales VALUES ('Laptop', '2023-01-15'), (NULL, '2023-01-10'), ('Mouse', '2023-01-20'), ('Keyboard', NULL);
SELECT arg_min_null(product, sale_date) FROM sales;
-- Result: NULL (because the earliest sale_date corresponds to a NULL product)

CREATE TABLE sales (product_name VARCHAR, sale_amount INT);
INSERT INTO sales VALUES ('Laptop', 1200), ('Mouse', 50), ('Keyboard', 75), ('Laptop', 1500);
SELECT argmax(product_name, sale_amount) FROM sales;
-- Returns: 'Laptop'

CREATE TABLE integers(i INTEGER);
INSERT INTO integers VALUES (7), (3);
SELECT bit_and(i) FROM integers; -- Result: 3

CREATE TABLE bitwise_test(g INT, i INT);
INSERT INTO bitwise_test VALUES (1, 3), (1, 5), (2, 7), (2, 1);
SELECT g, bit_or(i) FROM bitwise_test GROUP BY g;
-- g | bit_or(i)
-- 1 | 7
-- 2 | 7

CREATE TABLE integers(i INTEGER);
INSERT INTO integers VALUES (3), (5), (6);
SELECT bit_xor(i) FROM integers; -- Returns 0

CREATE TABLE students (course VARCHAR, type VARCHAR);
INSERT INTO students (course, type)
VALUES
    ('CS', 'Bachelor'), ('CS', 'Bachelor'), ('CS', 'PhD'), ('Math', 'Masters'),
    ('CS', NULL), ('CS', NULL), ('Math', NULL);

-- Counts all rows in the students table
SELECT count(*) FROM students;

CREATE SEQUENCE seq;
SELECT nextval('seq');
-- returns 1
SELECT currval('seq');
-- returns 1

SELECT function_name, parameters, parameter_types, return_type
FROM duckdb_functions()
WHERE function_name LIKE 'ST_%';

CREATE TABLE series AS SELECT column0 AS val FROM (VALUES (1.0), (2.0), (4.0), (8.0));

SELECT geomean(val) FROM series;
-- 2.8284271247461903

CREATE TABLE example (j JSON);
INSERT INTO example VALUES
    ('{ "family": "anatidae", "species": [ "duck", "goose", "swan", null ] }');
SELECT json(j) FROM example;

CREATE TABLE example (j JSON);
INSERT INTO example VALUES ('{"family": "anatidae", "species": ["duck", "goose"]}');
SELECT je.*
FROM example AS e, json_each(e.j) AS je;

CREATE TABLE example1 (k VARCHAR, v INTEGER);
INSERT INTO example1 VALUES ('duck', 42), ('goose', 7);
SELECT json_group_array(v) FROM example1;
-- Returns [42, 7]

CREATE TABLE items (name VARCHAR, price INT);
INSERT INTO items VALUES ('duck', 42), ('goose', 7);
SELECT json_group_object(name, price) FROM items;

CREATE TABLE example (j JSON);
INSERT INTO example VALUES
    ('{"family": "anatidae", "species": ["duck", "goose"], "coolness": 42.42}');

-- This will fail because 'anatidae' cannot be cast to TINYINT
SELECT json_transform_strict(j, '{"family": "TINYINT", "coolness": "DOUBLE"}') FROM example;

CREATE TABLE series(val DOUBLE);
INSERT INTO series VALUES (1), (2), (3), (4), (5), (10);
SELECT kurtosis(val) FROM series;

SELECT max(temp_lo) FROM weather;
-- Returns the top 3 populations for each country
SELECT country, max(population, 3) FROM cities GROUP BY country;

